import { Injectable } from "@angular/core";
import { AsyncSubject, Observable } from "rxjs";
import { map } from "rxjs/operators";
import { IStringMap, IUser } from "../base/core";
import { CoreBase } from "../base/runtime";
import { CommonDataService } from "../service";

@Injectable({
	providedIn: "root",
})
export class DisplayNameService extends CoreBase {
	private nameCache: IStringMap = {};

	constructor(private commonDataService: CommonDataService) {
		super("DisplayNameService");
	}

	getDisplayNames(userIds: string[]): Observable<IStringMap> {
		const subject = new AsyncSubject<IStringMap>();
		const idsNotInCache = userIds.filter((id) => !(id in this.nameCache));
		if (idsNotInCache && idsNotInCache.length > 0) {
			this.loadDisplayNames(idsNotInCache).subscribe((users) => {
				for (const user of users) {
					this.nameCache[user.userName] = user.displayName;
				}
				this.asyncComplete(subject, this.nameCache);
			});
		} else {
			this.asyncComplete(subject, this.nameCache);
		}
		return subject.asObservable();
	}

	private loadDisplayNames(userIds: string[]): Observable<IUser[]> {
		const distinctUsers = Array.from(new Set(userIds)).map((id) => {
			return { userName: id } as IUser;
		});
		return this.commonDataService
			.getNames(distinctUsers)
			.pipe(map((response) => response && response.content));
	}
}
